"""Unit tests for the json_path constraint converter.

These tests verify the JSONPath parser and the JSONPath-to-JSON-Schema
converter without requiring a running SGLang server.
"""

import json
import unittest

from sglang.srt.constrained.json_path_constraint import (
    ArrayIndexSegment,
    PropertySegment,
    WildcardSegment,
    json_path_to_json_schema,
    parse_json_path,
    validate_json_path,
)


class TestParseJsonPath(unittest.TestCase):
    """Tests for the JSONPath parser."""

    def test_root_only(self):
        segments = parse_json_path("$")
        self.assertEqual(segments, [])

    def test_simple_property(self):
        segments = parse_json_path("$.name")
        self.assertEqual(len(segments), 1)
        self.assertIsInstance(segments[0], PropertySegment)
        self.assertEqual(segments[0].name, "name")

    def test_nested_property(self):
        segments = parse_json_path("$.a.b.c")
        self.assertEqual(len(segments), 3)
        self.assertEqual(segments[0].name, "a")
        self.assertEqual(segments[1].name, "b")
        self.assertEqual(segments[2].name, "c")

    def test_bracket_notation(self):
        segments = parse_json_path("$['store']['book']")
        self.assertEqual(len(segments), 2)
        self.assertEqual(segments[0].name, "store")
        self.assertEqual(segments[1].name, "book")

    def test_bracket_double_quotes(self):
        segments = parse_json_path('$["store"]')
        self.assertEqual(len(segments), 1)
        self.assertEqual(segments[0].name, "store")

    def test_wildcard_dot(self):
        segments = parse_json_path("$.*")
        self.assertEqual(len(segments), 1)
        self.assertIsInstance(segments[0], WildcardSegment)

    def test_wildcard_bracket(self):
        segments = parse_json_path("$[*]")
        self.assertEqual(len(segments), 1)
        self.assertIsInstance(segments[0], WildcardSegment)

    def test_array_index(self):
        segments = parse_json_path("$.items[0]")
        self.assertEqual(len(segments), 2)
        self.assertIsInstance(segments[0], PropertySegment)
        self.assertIsInstance(segments[1], ArrayIndexSegment)
        self.assertEqual(segments[1].index, 0)

    def test_array_index_larger(self):
        segments = parse_json_path("$.items[2]")
        self.assertEqual(len(segments), 2)
        self.assertEqual(segments[1].index, 2)

    def test_complex_path(self):
        segments = parse_json_path("$.store.book[*].author")
        self.assertEqual(len(segments), 4)
        self.assertEqual(segments[0].name, "store")
        self.assertEqual(segments[1].name, "book")
        self.assertIsInstance(segments[2], WildcardSegment)
        self.assertEqual(segments[3].name, "author")

    def test_mixed_notation(self):
        segments = parse_json_path("$.store['book'][0].title")
        self.assertEqual(len(segments), 4)
        self.assertEqual(segments[0].name, "store")
        self.assertEqual(segments[1].name, "book")
        self.assertIsInstance(segments[2], ArrayIndexSegment)
        self.assertEqual(segments[2].index, 0)
        self.assertEqual(segments[3].name, "title")


